examples.source:
classDiagram
  class Renderer {
    +renderSVG(source) string
    +renderASCII(source) string
  }
  class Theme {
    +bg string
    +fg string
  }
  Renderer --> Theme : uses

erDiagram
  CUSTOMER {
    string id PK
    string email
  }
  ORDER {
    string id PK
    date created
  }
  LINE_ITEM {
    string id PK
    int quantity
  }
  CUSTOMER ||--o{ ORDER : places
  ORDER ||--|{ LINE_ITEM : contains

classDiagram
  class Renderer {
    +renderSVG(source) string
    +renderASCII(source) string
  }
  class StyleResolver {
    +resolveRenderStyle(options) object
  }
  Renderer --> StyleResolver : uses

erDiagram
  USER {
    string id PK
    string email
  }
  DIAGRAM {
    string id PK
    string source
  }
  EXPORT {
    string id PK
    string format
  }
  USER ||--o{ DIAGRAM : creates
  DIAGRAM ||--o{ EXPORT : renders
